module div_16bit(
    input [15:0] dividend,
    input [7:0] divisor,
    output reg [15:0] quotient,
    output reg [7:0] remainder
);

    reg [15:0] dividend_reg;
    reg [7:0] divisor_reg;
    reg [15:0] quotient_reg;
    reg [7:0] remainder_reg;

    always @(*) begin
        dividend_reg = dividend;
        divisor_reg = divisor;
        quotient_reg = 16'b0;
        remainder_reg = 8'b0;

        if (dividend_reg[15:8] >= divisor_reg) begin
            quotient_reg[15:8] = 8'b1;
            remainder_reg = dividend_reg[15:8] - divisor_reg;
        end else begin
            quotient_reg[15:8] = 8'b0;
            remainder_reg = dividend_reg[15:8];
        end

        quotient = quotient_reg;
        remainder = remainder_reg;
    end

endmodule
